SELECT total_energy
FROM steps
WHERE step_number = 1;

SELECT SUM(value) AS total_energy_sum
FROM step_energy_values
WHERE component_id = 0;

SELECT step_number, total_energy 
FROM steps 
ORDER BY total_energy DESC;

SELECT MAX(setting_value) AS max_temperature
FROM simulation_settings
WHERE setting_name = 'temperature';

SELECT step_id, value AS total_energy
FROM step_energy_values
WHERE component_id = 0;
